export const HEURISTIC_PATTERNS: HeuristicEntry[] = [
  { pattern: /(\d+(?:\.\d+)?)b(?:\b|[-_])/i, unit: 'B' },
  { pattern: /(\d+(?:\.\d+)?)m(?:\b|[-_])/i, unit: 'M' },
]

/** Normalize a model name for matching (lowercase, replace /_.  with -). */
export function normalizeModelName(name: string): string {
  return name.toLowerCase().replace(/[\/_.]/g, '-')
}

export interface ModelInfo {
  params_b: number
  context: number | null
  source: 'catalog' | 'heuristic' | 'config'
}

/**
 * Look up model intelligence by name.
 * Resolution: regex match → alias substring → heuristic extraction → null.
 */
export function lookupModel(rawName: string): ModelInfo | null {
  if (!rawName) return null
  const name = normalizeModelName(rawName)

  // 1. Regex pattern match (first match wins)
  for (const fam of MODEL_FAMILIES) {
    if (fam.pattern.test(name)) {
      return { params_b: fam.params_b, context: fam.context, source: 'catalog' }
    }
  }

  // 2. Alias substring match
  for (const fam of MODEL_FAMILIES) {
    for (const alias of fam.aliases) {
      if (name.includes(alias)) {
        return { params_b: fam.params_b, context: fam.context, source: 'catalog' }
      }
    }
  }

  // 3. Heuristic extraction
  for (const h of HEURISTIC_PATTERNS) {
    const m = name.match(h.pattern)
    if (m) {
      let val = parseFloat(m[1])
      if (h.unit === 'M') val /= 1000
      if (val > 0) return { params_b: val, context: null, source: 'heuristic' }
    }
  }

  return null
}
